import java.util.Set;

public class Solution {
    /**
     * Checks if a given subarray can be sorted by cyclic shifts.
     * A subarray can be sorted by cyclic shifts if and only if it is a permutation
     * of the sorted version of itself.
     * More specifically, if the elements are unique, it must be sorted.
     * If there are duplicates, it must be possible to achieve the sorted order.
     * The key insight here is that cyclic shifts only change the relative order
     * within the subarray; they don't change the multiset of elements.
     * To be sortable by cyclic shifts, the multiset of elements in the subarray
     * must match the multiset of elements in the corresponding segment of the
     * globally sorted array.
     * 
     * For the problem's context, if a subarray of length k can be cyclically shifted
     * to become sorted *relative to itself*, it means the elements within that subarray
     * must already be a permutation of some sequence that *is* sorted.
     * 
     * If a subarray is [a1, a2, ..., ak], and its sorted version is [s1, s2, ..., sk].
     * It can be sorted by cyclic shifts if and only if there exists a shift `j` such that
     * [a_{j+1}, ..., a_k, a_1, ..., a_j] == [s1, s2, ..., sk].
     * This is equivalent to checking if the original subarray is a cyclic shift of its sorted version.
     */
    private static boolean isCyclicShiftOfSorted(int[] arr) {
        int k = arr.length;
        if (k == 0) return true;
        if (k == 1) return true;

        // 1. Get the sorted version
        int[] sortedArr = Arrays.copyOf(arr, k);
        Arrays.sort(sortedArr);

        // 2. Check if arr is a cyclic shift of sortedArr
        // Concatenate sortedArr with itself: [s1, s2, ..., sk, s1, s2, ..., sk]
        // Then check if arr is a subarray of length k in this concatenated array.

        // Create a doubled array for easier searching
        int[] doubledSorted = new int[2 * k];
        for (int i = 0; i < 2 * k; i++) {
            doubledSorted[i] = sortedArr[i % k];
        }

        // Search for 'arr' within 'doubledSorted'
        for (int start = 0; start < k; start++) {
            boolean match = true;
            for (int i = 0; i < k; i++) {
                if (arr[i] != doubledSorted[start + i]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }
        return false;
    }

    /**
     * Checks if the entire array nums can be sorted by cyclically shifting
     * the k-sized blocks.
     * 
     * The condition for global sortability is that for every block, the elements
     * must be a permutation of the elements they should contain in the final sorted array.
     * Furthermore, since we can independently sort each block, the elements within 
     * a block can be placed in any order *relative to each other* that is achievable
     * by cyclic shifts. If we can place them in the sorted order, then the block is "sorted".
     * 
     * The crucial condition is: For every block, the multiset of elements in that block 
     * must match the multiset of elements in the corresponding segment of the overall sorted array.
     * If this condition holds, since cyclic shifts allow us to arrange the elements within 
     * the block arbitrarily (given enough shifts, which is true if k>1 and elements aren't all equal, but the cyclic shift check handles this), 
     * we can achieve the required sorted order within that block.
     * 
     * Let S be the sorted version of nums.
     * Block i (0-indexed) is nums[i*k : (i+1)*k].
     * Target Block i is S[i*k : (i+1)*k].
     * 
     * We must verify that the multiset of elements in Block i equals the multiset of elements in Target Block i, for all i.
     * If the multisets match, we can always sort the block using cyclic shifts if k > 1 and the block contains at least two distinct elements that are not adjacent in the sorted order, or simply by observing that if the multisets match, the block is a permutation of the target block. Since any permutation of a block can be achieved by *some* sequence of operations, and cyclic shifts are powerful, the multiset equality is the key necessary and sufficient condition here.
     * 
     * Given the problem constraint: "independently on each subarray, perform cyclic shifts", 
     * the ability to sort the array globally requires that for every block, the set of numbers 
     * currently in that block must be exactly the set of numbers that *should* be in that block 
     * in the final sorted array.
     */
    private static boolean isSortable(int[] nums, int k) {
        int n = nums.length;
        int[] sortedNums = Arrays.copyOf(nums, n);
        Arrays.sort(sortedNums);

        // Check if every block has the correct multiset of elements
        for (int i = 0; i * k < n; i++) {
            int start = i * k;
            int end = Math.min((i + 1) * k, n);
            int currentBlockSize = end - start;

            // Extract the current block
            int[] currentBlock = new int[currentBlockSize];
            System.arraycopy(nums, start, currentBlock, 0, currentBlockSize);

            // Extract the target block from the sorted array
            int[] targetBlock = new int[currentBlockSize];
            System.arraycopy(sortedNums, start, targetBlock, 0, currentBlockSize);

            // Check if multisets are equal (by sorting and comparing)
            Arrays.sort(currentBlock);
            Arrays.sort(targetBlock);

            if (!Arrays.equals(currentBlock, targetBlock)) {
                return false;
            }

            // Additional check: If the block size k > 1, we must ensure that the block itself 
            // can be sorted by cyclic shifts. If the multisets match, the block is a permutation
            // of the target block. If k=n, the whole array must be cyclically shiftable to sorted.
            // If k < n, the block must be cyclically shiftable *to the sorted version of that block*.

            if (currentBlockSize > 1) {
                // The multiset check ensures the *elements* are correct.
                // The cyclic shift check ensures the *arrangement* is reachable.
                if (!isCyclicShiftOfSorted(currentBlock)) {
                    return false;
                }
            }
            // If k=1, the block is always sorted, so the check passes implicitly.
        }
        return true;
    }

    public static long solve(long[] numsLong) {
        int n = numsLong.length;
        int[] nums = new int[n];
        for (int i = 0; i < n; i++) {
            nums[i] = (int) numsLong[i];
        }

        // 1. Find all divisors of n
        Set<Integer> divisors = new HashSet<>();
        for (int i = 1; i * i <= n; i++) {
