                divisors.add(i);
                divisors.add(n / i);
            }
        }

        long sumOfK = 0;

        // 2. Check each divisor k
        for (int k : divisors) {
            if (isSortable(nums, k)) {
                sumOfK += k;
            }
        }

        return sumOfK;
    }
