            for (int j = 0; j < k; j++) {
                targetBlock[j] = sortedNums[start + j];
            }

            // 3. Check if the multiset of elements in currentBlock matches the multiset of elements in targetBlock.
            // Since targetBlock is a segment of the globally sorted array, its elements are already sorted.
            // If we sort currentBlock, it must match targetBlock element by element.

            int[] sortedCurrentBlock = Arrays.copyOf(currentBlock, k);
            Arrays.sort(sortedCurrentBlock);

            if (!Arrays.equals(sortedCurrentBlock, targetBlock)) {
                return false;
            }
        }
        return true;
    }

    public static long solve(long[] numsLong) {
        int n = numsLong.length;
        int[] nums = new int[n];
        for (int i = 0; i < n; i++) {
            nums[i] = (int) numsLong[i];
        }

        // 1. Determine the target sorted array
        int[] sortedNums = Arrays.copyOf(nums, n);
        Arrays.sort(sortedNums);

        long sumK = 0;

        // 2. Find all divisors k of n
        List<Integer> divisors = new ArrayList<>();
        for (int k = 1; k * k <= n; k++) {
            if (n % k == 0) {
                divisors.add(k);
                if (k * k != n) {
                    divisors.add(n / k);
                }
            }
        }

        // 3. Check each divisor k
        for (int k : divisors) {
            // Edge case: k=1 always fails unless n=1, because a single element block
            // cannot be "reordered" relative to its neighbors, and the problem implies
            // some transformation capability.
            // However, the definition is: "independently on each subarray... perform cyclic shifts".
            // If k=1, each subarray is [x]. Cyclic shift of [x] is [x]. It can only be sorted if it already is.
            // If n>1, and k=1, the condition requires nums[i] == sortedNums[i] for all i.
            if (k == 1) {
                boolean alreadySorted = true;
                for (int i = 0; i < n; i++) {
                    if (nums[i] != sortedNums[i]) {
                        alreadySorted = false;
                        break;
                    }
                }
                if (alreadySorted) {
                    sumK += k;
                }
                continue; // Move to next k
            }

            // The critical insight from the problem constraints:
            // If we can sort each block independently using cyclic shifts, the *multiset*
            // of elements in each block must match the multiset of elements that *should*
            // be in that block in the final sorted array. Since the target array is globally sorted,
            // the target block is already sorted.

            if (checkK(nums, sortedNums, k)) {
